void SettingViewBase::setupScreen()
{

}

void SettingViewBase::buttonCallbackHandler(const touchgfx::AbstractButton& src)
{
    if (&src == &exit)
    {
        //exit
        //When exit clicked change screen to Test
        //Go to Test with no screen transition
        application().gotoTestScreenNoTransition();
    }
    if (&src == &nextPage)
    {
        //nextPage
        //When nextPage clicked change screen to Serify
        //Go to Serify with no screen transition
        application().gotoSerifyScreenNoTransition();
    }
    if (&src == &resetCounter)
    {
        //resetCounterClicked
        //When resetCounter clicked call virtual function
        //Call resetCounterClicked
        resetCounterClicked();
        //Interaction1
        //When resetCounter clicked change screen to Test
        //Go to Test with no screen transition
        application().gotoTestScreenNoTransition();
    }
}

